import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";

function FacultyDashboard() {

  const navigate = useNavigate();

  const { user, logout } = useAuth();

  const handleLogout = () => {

    logout();

    navigate("/login");
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        backgroundColor: "#f5f7fa",
        padding: "30px"
      }}
    >
      {/* Header */}

      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "30px"
        }}
      >
        <div>
          <h1>
            SRIHER IQAC Portal
          </h1>

          <h2>
            Welcome,
            {" "}
            {user?.name}
          </h2>
        </div>

        <button
          onClick={handleLogout}
          style={{
            padding: "10px 20px",
            cursor: "pointer"
          }}
        >
          Logout
        </button>
      </div>

      {/* Quarter Selection */}

      <h2>
        Select Quarter
      </h2>

      <div
        style={{
          display: "flex",
          gap: "15px",
          marginBottom: "30px"
        }}
      >
        {[
          "Q1",
          "Q2",
          "Q3",
          "Q4"
        ].map(
          (quarter) => (
            <button
              key={quarter}
              style={{
                padding:
                  "15px 30px",
                cursor: "pointer"
              }}
            >
              {quarter}
            </button>
          )
        )}
      </div>

      {/* Action Cards */}

      <h2>
        Faculty Actions
      </h2>

      <div
        style={{
          display: "flex",
          gap: "20px",
          flexWrap: "wrap"
        }}
      >

        <div
          style={{
            background:
              "#ffffff",
            padding: "20px",
            width: "250px",
            borderRadius:
              "10px",
            boxShadow:
              "0 2px 8px rgba(0,0,0,0.1)"
          }}
        >
          <h3>
            Questionnaire
          </h3>

          <p>
            Fill IQAC
            Questionnaire
          </p>

          <button
            onClick={() =>
              navigate(
                "/faculty/questionnaire"
              )
            }
          >
            Open
          </button>
        </div>

        <div
          style={{
            background:
              "#ffffff",
            padding: "20px",
            width: "250px",
            borderRadius:
              "10px",
            boxShadow:
              "0 2px 8px rgba(0,0,0,0.1)"
          }}
        >
          <h3>
            My Submissions
          </h3>

          <p>
            View Submitted
            Reports
          </p>

          <button
            onClick={() =>
              navigate(
                "/faculty/submissions"
              )
            }
          >
            View
          </button>
        </div>

        <div
          style={{
            background:
              "#ffffff",
            padding: "20px",
            width: "250px",
            borderRadius:
              "10px",
            boxShadow:
              "0 2px 8px rgba(0,0,0,0.1)"
          }}
        >
          <h3>
            Profile
          </h3>

          <p>
            Manage Profile
          </p>

          <button
            onClick={() =>
              navigate(
                "/profile"
              )
            }
          >
            Open
          </button>
        </div>

      </div>

      {/* Statistics */}

      <h2
        style={{
          marginTop:
            "40px"
        }}
      >
        Statistics
      </h2>

      <div
        style={{
          display: "flex",
          gap: "20px"
        }}
      >

        <div
          style={{
            background:
              "#ffffff",
            padding: "20px",
            width: "200px",
            borderRadius:
              "10px"
          }}
        >
          <h3>
            0
          </h3>

          <p>
            Total
            Submissions
          </p>
        </div>

        <div
          style={{
            background:
              "#ffffff",
            padding: "20px",
            width: "200px",
            borderRadius:
              "10px"
          }}
        >
          <h3>
            0
          </h3>

          <p>
            Drafts
          </p>
        </div>

        <div
          style={{
            background:
              "#ffffff",
            padding: "20px",
            width: "200px",
            borderRadius:
              "10px"
          }}
        >
          <h3>
            0
          </h3>

          <p>
            Pending HOD
            Approval
          </p>
        </div>

      </div>

    </div>
  );
}

export default FacultyDashboard;
